export const SEED_PROBLEMS: SeedProblem[] = RAW.map(([id, title, titleSlug, difficulty, acceptanceRate, likes, dislikes, isPremium, tags, companies]) => ({
  id, title, titleSlug, difficulty, acceptanceRate, likes, dislikes, isPremium, tags, companies,
}));

export function getAllSeedProblems(): SeedProblem[] { return SEED_PROBLEMS; }
export function getSeedProblemsByTags(tagNames: string[]): SeedProblem[] {
  return SEED_PROBLEMS.filter(p => p.tags.some(t => tagNames.includes(t)));
}